-- OpenResty Lua access control script

local function check_permissions()
    -- Get the authentication token from the request header
    local auth_token = ngx.req.get_headers()["Authorization"]
    
    if not auth_token then
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.say("Unauthorized")
        ngx.exit(ngx.HTTP_UNAUTHORIZED)
        return
    end
    
    -- Validate the authentication token (placeholder logic)
    if auth_token ~= "valid_token" then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Forbidden")
        ngx.exit(ngx.HTTP_FORBIDDEN)
        return
    end
    
    -- Get the user role from the request header or a database lookup
    local user_role = ngx.req.get_headers()["X-User-Role"]
    
    if not user_role then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Missing user role")
        ngx.exit(ngx.HTTP_BAD_REQUEST)
        return
    end
    
    -- Define allowed roles for certain endpoints
    local allowed_roles = {
        ["/admin"] = {"admin"},
        ["/api"] = {"admin", "user"}
    }
    
    -- Check if the current URI requires permission checking
    for endpoint, roles in pairs(allowed_roles) do
        if ngx.var.uri:find(endpoint) then
            local has_permission = false
            for _, role in ipairs(roles) do
                if user_role == role then
                    has_permission = true
                    break
                end
            end
            
            if not has_permission then
                ngx.status = ngx.HTTP_FORBIDDEN
                ngx.say("Forbidden")
                ngx.exit(ngx.HTTP_FORBIDDEN)
                return
            end
        end
    end
